/* BadwordFilterMapper.insertMessageBlockLog */
SELECT MESSAGE_BLOCK_LOG_SEQ.NEXTVAL FROM DUAL
INSERT INTO MESSAGE_BLOCK_LOG ( ID, ACCOUNT_ID, MESSAGE_ID, BLOCK_TYPE, TRIGGERED_KEYWORD_ID, TRIGGERED_URL, URL_CHECK_SOURCE, STATUS, ADMIN_REVIEW_ID, MESSAGE_SNIPPET, CREATED_AT, SMS_SEND_SEQ, CALLBACK, S_OGN_CD, S_OGN_FG, S_USER_ID ) VALUES ( #{blockLogId}, #{ssUserId}, #{msgId}, #{blockType}, #{triggeredKeywordId}, #{triggeredUrl}, #{urlCheckSource}, CASE WHEN #{triggeredStatus} = 'block' THEN 'blocked' WHEN #{triggeredStatus} = 'hold' THEN 'held' WHEN #{triggeredStatus} = 'warn' THEN 'warned' ELSE 'allowed' END, #{adminReviewId}, #{messageSnippet}, #{regDt}, #{smsSendSeq}, SBPENC.E(#{callback}), #{ssOrgnCd}, #{ssOrgnFg}, #{ssUserId} )
